@Composable
fun LoopsSlide(videoId: Long?, onDismiss: () -> Unit, viewModel: LoopsViewModel = hiltViewModel()) {
    val holder = LocalPlayerHolder.current; val playerState by holder.state.collectAsStateWithLifecycle()
    LaunchedEffect(videoId) { videoId?.let { viewModel.setActiveVideo(it) } }
    val loops by viewModel.loops.collectAsStateWithLifecycle(); var showCreateModal by remember { mutableStateOf(false) }; var openMenuId by remember { mutableStateOf<Long?>(null) }
    val progressFraction = if (playerState.durationMs > 0) (playerState.currentPositionMs.toFloat() / playerState.durationMs.toFloat()).coerceIn(0f, 1f) else 0f
    Column(modifier = Modifier.fillMaxSize().background(CactusColors.White)) {
        PlayerHeader(title = "Custom Loops", subtitle = "A-B Timeframes", onDismiss = onDismiss, rightAction = { Icon(Icons.Filled.Add, contentDescription = "New loop", tint = CactusColors.Neutral700, modifier = Modifier.size(22.dp).clickable(interactionSource = remember { MutableInteractionSource() }, indication = null, onClick = { showCreateModal = true })) })
        if (loops.isEmpty()) { Box(Modifier.fillMaxWidth().weight(1f), contentAlignment = Alignment.Center) { Column(horizontalAlignment = Alignment.CenterHorizontally) { Box(Modifier.size(64.dp).clip(RoundedCornerShape(50)).background(CactusColors.Neutral100), contentAlignment = Alignment.Center) { Icon(Icons.Filled.Repeat, contentDescription = null, tint = CactusColors.Neutral400, modifier = Modifier.size(28.dp)) }; Spacer(Modifier.height(20.dp)); Text("No loops yet", fontSize = 16.sp, fontWeight = FontWeight.Bold, color = CactusColors.Neutral800); Spacer(Modifier.height(8.dp)); Text("Tap + to drill a specific section", fontSize = 12.sp, color = CactusColors.Neutral500) } } }
        else { LazyColumn(modifier = Modifier.fillMaxWidth().weight(1f).padding(horizontal = 20.dp, vertical = 12.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) { items(loops) { loop -> Box { Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(12.dp)).border(1.dp, CactusColors.Neutral100, RoundedCornerShape(12.dp)).clickable(interactionSource = remember { MutableInteractionSource() }, indication = null) { viewModel.playLoop(loop, holder) }.padding(12.dp)) { Box(Modifier.size(40.dp).clip(RoundedCornerShape(8.dp)).background(CactusColors.Neutral100), contentAlignment = Alignment.Center) { Icon(Icons.Filled.Repeat, contentDescription = null, tint = CactusColors.Neutral700, modifier = Modifier.size(16.dp)) }; Spacer(Modifier.width(12.dp)); Column(Modifier.weight(1f)) { Text(loop.name, fontSize = 14.sp, fontWeight = FontWeight.SemiBold, color = CactusColors.Neutral900, maxLines = 1, overflow = TextOverflow.Ellipsis); Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.padding(top = 2.dp)) { Text(TimeUtils.formatDuration(loop.startMs), fontSize = 12.sp, color = CactusColors.Neutral500); Spacer(Modifier.width(6.dp)); Box(Modifier.width(12.dp).height(1.dp).background(CactusColors.Neutral300)); Spacer(Modifier.width(6.dp)); Text(TimeUtils.formatDuration(loop.endMs), fontSize = 12.sp, color = CactusColors.Neutral500); Text("  -  ", fontSize = 12.sp, color = CactusColors.Neutral300); Text("${loop.loopCount} Loops", fontSize = 12.sp, color = CactusColors.Neutral500) } }; Box(Modifier.size(32.dp).clip(RoundedCornerShape(50)).clickable(interactionSource = remember { MutableInteractionSource() }, indication = null) { openMenuId = if (openMenuId == loop.id) null else loop.id }, contentAlignment = Alignment.Center) { Icon(Icons.Filled.MoreVert, contentDescription = null, tint = CactusColors.Neutral400, modifier = Modifier.size(14.dp)) } }; DropdownMenu(expanded = openMenuId == loop.id, onDismissRequest = { openMenuId = null }, modifier = Modifier.width(112.dp)) { DropdownMenuItem(text = { Text("Delete", fontSize = 12.sp, fontWeight = FontWeight.Medium, color = CactusColors.Red500) }, onClick = { viewModel.deleteLoop(loop.id); openMenuId = null }) } } } } }
        PlayerDock(progressFraction = progressFraction, currentTimeLabel = TimeUtils.formatDuration(playerState.currentPositionMs), totalTimeLabel = TimeUtils.formatDuration(playerState.durationMs), centerButtonLabel = if (playerState.isPlaying) "Pause" else "Play", isPlaying = playerState.isPlaying, onCenterClick = { holder.togglePlayPause() }, onSeekBack = { holder.seekRelative(-15_000L) }, onSeekForward = { holder.seekRelative(15_000L) })
        PaginationDots(activeIndex = 2)
    }
    if (showCreateModal && videoId != null) { CreateLoopModal(onDismiss = { showCreateModal = false }, onSave = { name, start, end, count -> viewModel.createLoop(videoId, name, parseTimeToMs(start), parseTimeToMs(end), count); showCreateModal = false }) }
}
@Composable
private fun CreateLoopModal(onDismiss: () -> Unit, onSave: (String, String, String, Int) -> Unit) {
    var name by remember { mutableStateOf("") }; var start by remember { mutableStateOf("00:12") }; var end by remember { mutableStateOf("00:16") }; var count by remember { mutableStateOf("10") }
    Box(Modifier.fillMaxSize().background(CactusColors.Black.copy(alpha = 0.4f)).clickable(interactionSource = remember { MutableInteractionSource() }, indication = null, onClick = onDismiss), contentAlignment = Alignment.Center) {
        val scale by animateFloatAsState(1f, tween(350), label = "modal")
        Surface(shape = RoundedCornerShape(16.dp), color = CactusColors.White, modifier = Modifier.padding(horizontal = 20.dp).fillMaxWidth().scale(scale).clickable(interactionSource = remember { MutableInteractionSource() }, indication = null, onClick = {}).padding(20.dp)) {
            Column { Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) { Text("Create Custom Loop", fontSize = 18.sp, fontWeight = FontWeight.Bold, color = CactusColors.Black); Icon(Icons.Filled.Close, contentDescription = null, tint = CactusColors.Neutral400, modifier = Modifier.size(24.dp).clickable(interactionSource = remember { MutableInteractionSource() }, indication = null, onClick = onDismiss)) }; Spacer(Modifier.height(16.dp)); Text("LOOP NAME", fontSize = 10.sp, fontWeight = FontWeight.Bold, color = CactusColors.Neutral500, modifier = Modifier.padding(bottom = 4.dp)); OutlinedTextField(value = name, onValueChange = { name = it }, singleLine = true, placeholder = { Text("e.g., Hard Sentence 1", fontSize = 14.sp, color = CactusColors.Neutral500) }, shape = RoundedCornerShape(8.dp), colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = CactusColors.Black, unfocusedBorderColor = CactusColors.Neutral200, unfocusedContainerColor = CactusColors.Neutral100), modifier = Modifier.fillMaxWidth()); Spacer(Modifier.height(12.dp)); Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) { Column(Modifier.weight(1f)) { Text("START (A)", fontSize = 10.sp, fontWeight = FontWeight.Bold, color = CactusColors.Neutral500, modifier = Modifier.padding(bottom = 4.dp)); OutlinedTextField(value = start, onValueChange = { start = it }, singleLine = true, shape = RoundedCornerShape(8.dp), colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = CactusColors.Black, unfocusedBorderColor = CactusColors.Neutral200, unfocusedContainerColor = CactusColors.Neutral100), modifier = Modifier.fillMaxWidth()) }; Column(Modifier.weight(1f)) { Text("END (B)", fontSize = 10.sp, fontWeight = FontWeight.Bold, color = CactusColors.Neutral500, modifier = Modifier.padding(bottom = 4.dp)); OutlinedTextField(value = end, onValueChange = { end = it }, singleLine = true, shape = RoundedCornerShape(8.dp), colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = CactusColors.Black, unfocusedBorderColor = CactusColors.Neutral200, unfocusedContainerColor = CactusColors.Neutral100), modifier = Modifier.fillMaxWidth()) } }; Spacer(Modifier.height(12.dp)); Text("LOOP COUNT", fontSize = 10.sp, fontWeight = FontWeight.Bold, color = CactusColors.Neutral500, modifier = Modifier.padding(bottom = 4.dp)); OutlinedTextField(value = count, onValueChange = { count = it.filter { c -> c.isDigit() } }, singleLine = true, keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number), shape = RoundedCornerShape(8.dp), colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = CactusColors.Black, unfocusedBorderColor = CactusColors.Neutral200, unfocusedContainerColor = CactusColors.Neutral100), modifier = Modifier.fillMaxWidth()); Spacer(Modifier.height(20.dp)); Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) { Button(onClick = onDismiss, shape = RoundedCornerShape(8.dp), colors = ButtonDefaults.buttonColors(containerColor = CactusColors.Neutral100, contentColor = CactusColors.Neutral700), modifier = Modifier.weight(1f)) { Text("Cancel", fontSize = 14.sp, fontWeight = FontWeight.Bold) }; Button(onClick = { onSave(name, start, end, count.ifBlank { "1" }.toInt()) }, shape = RoundedCornerShape(8.dp), colors = ButtonDefaults.buttonColors(containerColor = CactusColors.Black, contentColor = CactusColors.White), modifier = Modifier.weight(1f)) { Text("Save Loop", fontSize = 14.sp, fontWeight = FontWeight.Bold) } } }
        }
    }
}
private fun parseTimeToMs(time: String): Long { val parts = time.split(":"); if (parts.size != 2) return 0L; return ((parts[0].toLongOrNull() ?: 0L) * 60 + (parts[1].toLongOrNull() ?: 0L)) * 1000 }
